const httpRequest = async (opts) => { const r = await fetch(opts.url, { method: opts.method || 'GET', headers: opts.headers, body: opts.body }); const t = await r.text(); try { return JSON.parse(t); } catch(e) { return t; } };
const child = $input.item.json;
const headers = { 'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk', 'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk' };
const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString();
const sevenDaysAgo = new Date(new Date(todayStart).getTime() - 7 * 86400000).toISOString();
let sessions = [], reactions = [], dynamicContext = {}, previousBrief = null, pushSubscription = null;

try {
  sessions = await httpRequest({ method: 'GET', url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/story_sessions?child_id=eq.${child.id}&created_at=gte.${sevenDaysAgo}&created_at=lt.${todayStart}&order=created_at.asc&select=*`, headers }) || [];
} catch(e) { console.log('Sessions fetch error:', e.message); }

try {
  reactions = await httpRequest({ method: 'GET', url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/morning_reactions?child_id=eq.${child.id}&generated_at=gte.${sevenDaysAgo}&select=observations,reactions,night_type,skipped,generated_at`, headers }) || [];
} catch(e) { console.log('Reactions fetch error:', e.message); }

try {
  const ctx = await httpRequest({ method: 'GET', url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/child_dynamic_context?child_id=eq.${child.id}&limit=1&select=*`, headers });
  dynamicContext = Array.isArray(ctx) && ctx.length > 0 ? ctx[0] : {};
} catch(e) { console.log('Dynamic context error:', e.message); }

try {
  const briefs = await httpRequest({ method: 'GET', url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/weekly_briefs?child_id=eq.${child.id}&order=created_at.desc&limit=1&select=brief_text,week_start`, headers });
  previousBrief = Array.isArray(briefs) && briefs.length > 0 ? briefs[0] : null;
} catch(e) { console.log('Previous brief error:', e.message); }

try {
  const prefs = await httpRequest({ method: 'GET', url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/notification_preferences?user_id=eq.${child.user_id}&child_id=eq.${child.id}&limit=1&select=push_subscription`, headers });
  pushSubscription = Array.isArray(prefs) && prefs.length > 0 ? prefs[0].push_subscription : null;
} catch(e) { console.log('Prefs fetch error:', e.message); }

return [{ json: {
  session_count: sessions.length,
  has_minimum_sessions: sessions.length >= 3,
  sessions,
  reactions,
  dynamicContext,
  previousBrief,
  pushSubscription,
  child,
  week_start: sevenDaysAgo
} }];

const { sessions, reactions, dynamicContext: ctx, previousBrief, pushSubscription, child, week_start } = $input.item.json;
const coCount = sessions.filter(s => s.night_type === 'co_creation').length;
const pbCount = sessions.filter(s => s.night_type === 'playback').length;
const total = sessions.length;

const sessionLines = sessions.map(s => {
  const d = new Date(s.created_at).toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' });
  return s.night_type === 'playback'
    ? `- ${d} | PLAYBACK | Story: "${s.source_story_title || 'Unknown'}" | Played ${s.playback_count_14d ?? '?'}x in 14 days | Parent note: ${s.parent_note || 'None'}`
    : `- ${d} | CO-CREATION | Prompt: "${s.story_prompt || 'None'}" | Themes: ${(s.themes || []).join(', ') || 'None'} | Parent note: ${s.parent_note || 'None'}`;
}).join('\n');

const reactionSummary = reactions.length > 0
  ? reactions.map(r => {
      if (r.skipped) return '- [SKIPPED — parent did not engage]';
      const lines = (r.observations || []).map((o, i) => {
        const rxn = (r.reactions || [])[i];
        const label = rxn === 'noticed' ? '✓ Noticed this' : rxn === 'unsure' ? '~ Not sure' : rxn === 'didnt_see' ? '✗ Didn\'t see that' : '(no reaction recorded)';
        return `  ${o.type}: "${o.text}" → ${label}`;
      }).join('\n');
      return `[${r.night_type}]\n${lines}`;
    }).join('\n')
  : 'No morning reactions this week — either first week or parent has not engaged with popups yet.';

const allies = (ctx.characters || []).filter(c => c.name).map(c => `${c.name} (${c.role || 'ally'})`).join(', ') || 'None noted';

const systemPrompt = `You are a compassionate child development observer writing a weekly brief for a parent. Plain language, warm, non-alarmist. Never clinical, never diagnostic.\n\nStructure your response with exactly these three labelled sections:\n\nHIGHLIGHTS\n2-4 sentences. The most significant emotional or thematic story across this week's sessions. Must be specific to this child and this week — not generic.\n\nPATTERNS\n2-4 sentences. Only name a pattern if at least two separate nights point in the same direction. If no genuine pattern exists write: "Nothing clear enough to name this week." Do not manufacture patterns from thin data. If the child had more playback nights than co-creation nights this week, name that explicitly — it is a meaningful signal worth surfacing.\n\nWHAT TO WATCH\n2 sentences. One specific, forward-looking lens for the parent in the week ahead. Not a task — something to notice or gently explore based on what this week suggests.\n\nMaximum 200 words total. Weight observations that received parent 'Noticed this' reactions more heavily. Do not repeat what was covered in last week's brief unless there is clear continuation.`;

const userPrompt = `CHILD: ${child.name}, age ${child.age}${child.gender_pronoun ? `, pronouns: ${child.gender_pronoun}` : ''}.\nPersonality: ${child.personality_description || 'Not provided'}.\nNeuro profile: ${child.neuro_profile || 'Not specified'}. Flags: ${(child.neuro_flags || []).join(', ') || 'None'}.\nInterests: ${(child.interests || []).join(', ') || 'Not specified'}.\nFamily: ${child.family_structure || 'Not provided'}.\nFear landscape: ${(ctx.fear_flags || []).join(', ') || 'None noted'}.\nCurrent stressors: ${ctx.current_stressors || 'None noted'}.\nAllies: ${allies}.\n\nSESSIONS THIS WEEK (${total} total — ${coCount} co-creation, ${pbCount} playback):\n${sessionLines}\n\nMORNING REACTIONS THIS WEEK:\n${reactionSummary}\n\nLAST WEEK'S BRIEF:\n${previousBrief ? `Week of ${previousBrief.week_start}: ${previousBrief.brief_text}` : 'No previous brief — this is the first week.'}\n\nWrite the weekly brief now.`;

return [{ json: {
  systemPrompt,
  userPrompt,
  child_id: child.id,
  user_id: child.user_id,
  child_name: child.name,
  week_start: week_start.split('T')[0],
  total_nights: total,
  co_creation_nights: coCount,
  playback_nights: pbCount,
  pushSubscription
} }];

const httpRequest = async (opts) => { const r = await fetch(opts.url, { method: opts.method || 'GET', headers: opts.headers, body: opts.body }); const t = await r.text(); try { return JSON.parse(t); } catch(e) { return t; } };
const claudeResponse = $input.item.json;
const prev = $('Build Brief Prompt').item.json;
const briefText = claudeResponse.content?.[0]?.text || '';

if (!briefText) {
  throw new Error('Claude returned empty brief');
}

const headers = {
  'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk',
  'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk',
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

await httpRequest({
  method: 'POST',
  url: 'https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/weekly_briefs',
  headers,
  body: JSON.stringify({
    child_id: prev.child_id,
    user_id: prev.user_id,
    brief_text: briefText,
    week_start: prev.week_start,
    total_nights: prev.total_nights,
    co_creation_nights: prev.co_creation_nights,
    playback_nights: prev.playback_nights,
    status: 'delivered',
    created_at: new Date().toISOString()
  })
});

if (prev.pushSubscription) {
  await httpRequest({
    method: 'POST',
    url: 'https://your-lambda-url.com',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      subscription: prev.pushSubscription,
      payload: {
        title: `${prev.child_name}'s weekly brief is ready ✨`,
        body: "This week's bedtime patterns — tap to read.",
        tag: 'weekly-brief',
        data: { type: 'weekly_brief', child_id: prev.child_id }
      }
    })
  }).catch(e => console.log('Push failed (non-fatal):', e.message));
}

return [{ json: { done: true, child_id: prev.child_id } }];
